INSERT INTO `blog_posts` (`id`, `title`, `slug`, `excerpt`, `content`, `featured_image`, `category`, `tags`, `author_name`, `is_published`, `is_featured`, `views`, `published_at`, `created_at`, `updated_at`) VALUES
(1, 'Annual Report 2024: A Year of Impact', 'annual-report-2024', 'Looking back at the milestones achieved in 2024 and the lives we touched together.', '<p>As we conclude another year at Dhrub Foundation, we reflect on the incredible journey we\'ve shared with our donors, volunteers, and beneficiaries.</p>\n\n<h3>Key Highlights</h3>\n<ul>\n<li>Reached 1000+ beneficiaries across West Bengal</li>\n<li>Launched 3 new programs in education and healthcare</li>\n<li>Expanded volunteer network to 75+ active members</li>\n<li>Raised ₹25 Lakhs in donations</li>\n</ul>\n\n<h3>Looking Ahead</h3>\n<p>In 2025, we plan to expand our reach to 5 new districts and launch a digital literacy program for rural youth.</p>\n\n<p>Thank you to everyone who made this possible. Together, we rise by lifting others.</p>', NULL, 'announcement', 'annual-report,2024,impact', 'Dhrub Foundation', 1, 1, 0, '2026-02-19 14:31:47', '2026-02-19 14:31:47', '2026-02-19 14:31:47'),
(2, 'Medical Camp Successfully Conducted in Sundarbans', 'medical-camp-sundarbans-2024', 'Our healthcare team provided free medical checkups and medicines to over 300 villagers.', '<p>Last weekend, our team of volunteer doctors and healthcare workers conducted a free medical camp in the remote villages of Sundarbans.</p>\n\n<h3>Services Provided</h3>\n<ul>\n<li>General health checkups</li>\n<li>Eye examinations</li>\n<li>Blood pressure and diabetes screening</li>\n<li>Free medicines distribution</li>\n</ul>\n\n<h3>Impact Numbers</h3>\n<p>Over 300 patients were examined, and 50+ were referred for specialized treatment at district hospitals. Special thanks to Dr. Amit Roy and his team for leading this initiative.</p>\n\n<p>If you\'re a medical professional interested in volunteering, please contact us!</p>', NULL, 'event', 'medical-camp,healthcare,sundarbans', 'Healthcare Team', 1, 0, 0, '2026-02-12 14:31:47', '2026-02-19 14:31:47', '2026-02-19 14:31:47'),
(3, 'Education Support Program Enrollment Open', 'education-enrollment-2025', 'We are now accepting applications for our 2025 Education Support Program for underprivileged students.', '<p>Dhrub Foundation is pleased to announce that enrollment for our 2025 Education Support Program is now open.</p>\n\n<h3>What We Offer</h3>\n<ul>\n<li>Full or partial school fee coverage</li>\n<li>School uniforms and supplies</li>\n<li>After-school tutoring support</li>\n<li>Monthly stipends for deserving students</li>\n</ul>\n\n<h3>Eligibility</h3>\n<ul>\n<li>Students from families with annual income below ₹1,00,000</li>\n<li>Currently enrolled in classes 1-12</li>\n<li>Resident of West Bengal</li>\n</ul>\n\n<p>Applications close on January 31, 2025. Apply now!</p>', NULL, 'announcement', 'education,enrollment,scholarship', 'Education Team', 1, 0, 0, '2026-02-16 14:31:47', '2026-02-19 14:31:47', '2026-02-19 14:31:47'),
(4, 'Volunteer Spotlight: Meet Priya Sen', 'volunteer-spotlight-priya-sen', 'Our dedicated volunteer Priya shares her journey of making a difference with Dhrub Foundation.', '<p>This month, we celebrate Priya Sen, who has been volunteering with us for over 2 years.</p>\n\n<h3>Priya\'s Story</h3>\n<p>\"I joined Dhrub Foundation after attending one of their medical camps. Seeing the joy on people\'s faces when they received basic healthcare made me realize how much impact we can create with simple acts of kindness.\"</p>\n\n<p>Priya has contributed over 500 hours of volunteer work, primarily in our education programs where she tutors underprivileged children on weekends.</p>\n\n<h3>Her Message to Aspiring Volunteers</h3>\n<p>\"Don\'t wait for the perfect time. Start small, but start now. The satisfaction of helping others is unparalleled.\"</p>\n\n<p>Want to be like Priya? Join our volunteer team today!</p>', NULL, 'story', 'volunteer,spotlight,inspiration', 'Volunteer Team', 1, 0, 0, '2026-02-05 14:31:47', '2026-02-19 14:31:47', '2026-02-19 14:31:47'),
(5, 'New Partnership with Local Schools Announced', 'school-partnership-2024', 'We\'ve partnered with 10 government schools to provide educational resources and support.', '<p>We are excited to announce our new partnership with 10 government schools across Kolkata and surrounding districts.</p>\n\n<h3>Partnership Highlights</h3>\n<ul>\n<li>Library books and educational materials</li>\n<li>Science lab equipment for practical learning</li>\n<li>Computer literacy programs</li>\n<li>Career counseling sessions</li>\n</ul>\n\n<h3>Benefiting Students</h3>\n<p>This partnership will directly benefit over 3,000 students from underprivileged backgrounds. Our goal is to bridge the educational resource gap and provide equal opportunities for all.</p>\n\n<p>We thank the District Education Department for making this possible.</p>', NULL, 'news', 'partnership,education,schools', 'Dhrub Foundation', 1, 0, 0, '2026-01-29 14:31:47', '2026-02-19 14:31:47', '2026-02-19 14:31:47'),
(9, 'New Education Center Opens in Rural Bengal', 'education-center-bengal', 'We are proud to announce the opening of our 15th education center, bringing quality education closer to underprivileged children.', '<p>We are thrilled to announce the opening of our 15th education center in Bankura district, bringing quality education closer to over 200 children.</p>', NULL, 'news', NULL, NULL, 1, 0, 0, '2024-02-20 10:00:00', '2026-02-20 09:22:54', '2026-02-20 09:22:54'),
(10, 'Healthcare Camp Benefits 500+ Families', 'healthcare-camp-2024', 'Our recent healthcare camp provided free medical check-ups, medicines, and referrals to over 500 families in need.', '<p>Our recent healthcare camp was a huge success, providing essential medical services to families who otherwise have no access to healthcare.</p>', NULL, '', NULL, NULL, 1, 0, 0, '2024-03-10 10:00:00', '2026-02-20 09:22:54', '2026-02-20 09:22:54');

