--
-- Table structure for table `success_stories`
--

CREATE TABLE `success_stories` (
  `id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `beneficiary_name` varchar(255) NOT NULL,
  `age` int(11) DEFAULT NULL,
  `location` varchar(255) DEFAULT NULL,
  `program_id` int(11) DEFAULT NULL,
  `story` text NOT NULL,
  `quote` text DEFAULT NULL,
  `impact` varchar(255) DEFAULT NULL,
  `image_path` varchar(500) DEFAULT NULL,
  `is_featured` tinyint(1) DEFAULT 0,
  `is_published` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_uca1400_ai_ci;

--
-- Dumping data for table `success_stories`
--

INSERT INTO `success_stories` (`id`, `title`, `beneficiary_name`, `age`, `location`, `program_id`, `story`, `quote`, `impact`, `image_path`, `is_featured`, `is_published`, `created_at`, `updated_at`) VALUES
(1, 'Riya\'s Journey to Education', 'Riya Das', 12, 'Kolkata, West Bengal', 1, 'Riya was struggling to continue her education due to financial constraints. Her father, a daily wage laborer, could barely afford one meal a day. Through our Education Support program, we provided Riya with school fees, uniforms, books, and monthly stipends. Today, she is a topper in her class and dreams of becoming a doctor to serve her community.', 'Dhrub Foundation gave me hope when I had none. Now I know that dreams can come true with hard work and support.', '85% improvement in academics within one year', NULL, 1, 1, '2026-02-19 14:31:47', '2026-02-19 14:31:47'),
(2, 'A Village Gets Clean Water', 'Rampur Village Community', NULL, 'Sundarbans, West Bengal', 2, 'The residents of Rampur village had to walk 3 kilometers every day to fetch contaminated water. Waterborne diseases were common, especially among children. Dhrub Foundation installed a deep tube well and water purification system, benefiting over 200 families. The incidence of waterborne diseases has dropped by 90% since the installation.', 'Our children no longer fall sick from drinking water. This is the greatest gift we could have received.', '200+ families now have access to clean drinking water', NULL, 0, 1, '2026-02-19 14:31:47', '2026-02-19 14:31:47'),
(3, 'Meena\'s Tailoring Business', 'Meena Bibi', 35, 'Howrah, West Bengal', 3, 'After losing her husband, Meena was left with three children and no source of income. She joined our Women Empowerment program where she learned tailoring skills. We provided her with a sewing machine and initial raw materials. Today, Meena runs her own tailoring shop and earns ₹15,000 per month, supporting her family independently.', 'I went from being dependent to being a provider. My children look up to me now, and that feeling is priceless.', 'Self-sufficient family, earns ₹15,000/month, employs 2 others', NULL, 0, 1, '2026-02-19 14:31:47', '2026-02-19 14:31:47'),
(4, 'Medical Camp Saves Lives', 'Sundarban Community', NULL, 'South 24 Parganas', 2, 'In remote areas of Sundarbans, access to healthcare is extremely limited. Our medical camps brought doctors, medicines, and health screenings to these communities. In one camp alone, we detected 15 cases of diabetes, 8 cases of hypertension, and provided treatment for over 300 patients. Early detection through these camps has literally saved lives.', 'The doctors came to us when we couldn\'t go to them. Many of us discovered health issues we didn\'t even know we had.', '500+ patients treated, 23 critical cases referred', NULL, 0, 1, '2026-02-19 14:31:47', '2026-02-19 14:31:47'),
(5, 'From Street to School', 'Rahul & Friends', 10, 'Sealdah, Kolkata', 1, 'Rahul and his friends spent their days collecting waste near Sealdah station. Our volunteers identified these children and enrolled them in our bridge school program. After 6 months of learning basic literacy and numeracy, all 12 children were admitted to nearby government schools. We continue to support them with after-school tuition and meals.', 'I can read now! I read the signboards on the trains and feel so proud.', '12 street children enrolled in formal education', NULL, 0, 1, '2026-02-19 14:31:47', '2026-02-19 14:31:47'),
(6, 'Nutrition Program for Mothers', 'Anganwadi Centers', NULL, 'North Bengal', 4, 'Malnutrition among pregnant women and newborns was a serious concern in remote villages of North Bengal. Our nutrition program partnered with local Anganwadi centers to provide fortified meals, iron supplements, and nutritional counseling. Over 18 months, we\'ve seen a 40% reduction in underweight births in the covered areas.', 'My baby was born healthy and strong. The nutrition support made all the difference during my pregnancy.', '500+ pregnant women supported, 40% reduction in underweight births', NULL, 0, 1, '2026-02-19 14:31:47', '2026-02-19 14:31:47'),
(7, 'From Streets to School', 'Rahul Kumar', 16, NULL, NULL, 'Rahul lived on the streets of Kolkata for three years after losing his parents. Our team found him at a railway station, malnourished and alone. Through our rehabilitation program, he received food, shelter, and psychological support. Today, he attends a local school and dreams of becoming a doctor to help others like him.', NULL, NULL, NULL, 0, 1, '2026-02-20 09:14:27', '2026-02-20 09:14:27'),
(8, 'A New Beginning for Sisters', 'Priya & Anita Sharma', 12, NULL, NULL, 'Priya (12) and her younger sister Anita (10) were found begging on the streets with their mother who was suffering from illness. Our team provided medical treatment for the mother and enrolled both girls in school. They now attend school regularly, receive tutoring support, and dream of becoming teachers.', NULL, NULL, NULL, 0, 1, '2026-02-20 09:14:27', '2026-02-20 09:14:27'),
(9, 'Healthcare Changed His Life', 'Mohammed Ali', 8, NULL, NULL, 'Mohammed was suffering from a severe eye condition that went untreated due to poverty. Through our healthcare program, he received the surgery he needed. Now he can see clearly and has been enrolled in school for the first time in his life.', NULL, NULL, NULL, 0, 1, '2026-02-20 09:14:27', '2026-02-20 09:14:27'),
(10, 'Skills for a Better Future', 'Sunita Devi', 28, NULL, NULL, 'Sunita, a single mother of three, joined our skill development program to learn tailoring. Within a year, she started her own small business from home. Today, she earns enough to support her family and send all her children to school.', NULL, NULL, NULL, 0, 1, '2026-02-20 09:14:27', '2026-02-20 09:14:27'),
(11, 'From Streets to School', 'Rahul Kumar', 16, NULL, NULL, 'Rahul lived on the streets of Kolkata for three years after losing his parents. Our team found him at a railway station, malnourished and alone. Through our rehabilitation program, he received food, shelter, and psychological support. Today, he attends a local school and dreams of becoming a doctor to help others like him.', NULL, NULL, NULL, 0, 1, '2026-02-20 09:22:54', '2026-02-20 09:22:54'),
(12, 'A New Beginning for Sisters', 'Priya & Anita Sharma', 12, NULL, NULL, 'Priya (12) and her younger sister Anita (10) were found begging on the streets with their mother who was suffering from illness. Our team provided medical treatment for the mother and enrolled both girls in school. They now attend school regularly, receive tutoring support, and dream of becoming teachers.', NULL, NULL, NULL, 0, 1, '2026-02-20 09:22:54', '2026-02-20 09:22:54'),
(13, 'Healthcare Changed His Life', 'Mohammed Ali', 8, NULL, NULL, 'Mohammed was suffering from a severe eye condition that went untreated due to poverty. Through our healthcare program, he received the surgery he needed. Now he can see clearly and has been enrolled in school for the first time in his life.', NULL, NULL, NULL, 0, 1, '2026-02-20 09:22:54', '2026-02-20 09:22:54'),
(14, 'Skills for a Better Future', 'Sunita Devi', 28, NULL, NULL, 'Sunita, a single mother of three, joined our skill development program to learn tailoring. Within a year, she started her own small business from home. Today, she earns enough to support her family and send all her children to school.', NULL, NULL, NULL, 0, 1, '2026-02-20 09:22:54', '2026-02-20 09:22:54');

